import React, { useEffect } from "react";
import "./Main.css";
import Aos from "aos";
import "aos/dist/aos.css";
import { Link } from "react-router-dom";

function Main({ images }) {
  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);

  function scrollToElement() {
    const targetElement = document.getElementById("main");
    if (targetElement) {
      targetElement.scrollIntoView({ behavior: "smooth" });
    }
  }
  return (
    <section id="main" className="main container section">
      <div className="secTitle">
        <div className="scrollDown" onClick={scrollToElement}>
          <span></span>
          <span></span>
          <span></span>
        </div>
        <h3 data-aos="fade-right" data-aos-duration="1200" className="title">
          Take A Look At Our Products
        </h3>
      </div>
      <div className="secContent grid">
        {images.map((image, index) => {
          return (
            <Link key={index} to={`/Product/${index}`}>
              <div
                data-aos="fade-up"
                data-aos-duration="1200"
                key={index}
                className={"singleProduct"}
              >
                <div className="imageDiv">
                  <img src={image.image} alt={image.title}></img>
                </div>
                <div className="cardInfo">
                  <h4 className="productTitle">{image.title}</h4>
                  <div className="desc">
                    <p>{image.description}</p>
                  </div>
                </div>
              </div>
            </Link>
          );
        })}
      </div>
    </section>
  );
}

export default Main;
